    var previousClose: Double
    var change: Double { currentPrice - previousClose }
    var changePercent: Double { (change / previousClose) * 100 }
    var bid: Double
    var ask: Double
    var volume: Int
    var timestamp: Date
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    var totalValue: Double { quantity * currentPrice }
    var totalCost: Double { quantity * averageCost }
    var profitLoss: Double { totalValue - totalCost }
    var profitLossPercent: Double { (profitLoss / totalCost) * 100 }
}

struct Portfolio: Codable {
    var positions: [Position]
    var cashBalance: Double
    var totalValue: Double { positions.reduce(cashBalance) { $0 + $1.totalValue } }
