// MARK: - Secure Keychain Manager

final class KeychainManager {
    static let shared = KeychainManager()
    private init() {}
    
    enum KeychainError: Error {
        case duplicateEntry
        case unknown(OSStatus)
        case itemNotFound
        case encodingError
    }
    
    func save(key: String, data: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        let status = SecItemAdd(query as CFDictionary, nil)
        
        if status == errSecDuplicateItem {
            let updateQuery: [String: Any] = [
                kSecClass as String: kSecClassGenericPassword,
                kSecAttrAccount as String: key
            ]
            let updateAttributes: [String: Any] = [
                kSecValueData as String: data
            ]
            let updateStatus = SecItemUpdate(updateQuery as CFDictionary, updateAttributes as CFDictionary)
            guard updateStatus == errSecSuccess else {
                throw KeychainError.unknown(updateStatus)
            }
        } else if status != errSecSuccess {
            throw KeychainError.unknown(status)
        }
    }
    
    func retrieve(key: String) throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            throw KeychainError.itemNotFound
        }
        return data
    }
    
    func delete(key: String) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unknown(status)
        }
    }
    
    func saveToken(_ token: String) throws {
        guard let data = token.data(using: .utf8) else {
            throw KeychainError.encodingError
        }
        try save(key: "auth_token", data: data)
    }
    
    func getToken() throws -> String {
        let data = try retrieve(key: "auth_token")
        guard let token = String(data: data, encoding: .utf8) else {
            throw KeychainError.encodingError
        }
        return token
    }
}

// MARK: - Network Layer

enum APIError: Error, LocalizedError {
    case invalidURL
    case unauthorized
    case serverError(Int)
    case decodingError
    case networkError(Error)
    case rateLimited
    case insufficientFunds
    case marketClosed
    case invalidOrder
    case timeout
    
    var errorDescription: String? {
        switch self {
        case .invalidURL: return "Invalid URL"
        case .unauthorized: return "Authentication required. Please log in again."
        case .serverError(let code): return "Server error (\(code))"
        case .decodingError: return "Failed to process response"
        case .networkError(let error): return error.localizedDescription
        case .rateLimited: return "Too many requests. Please wait."
        case .insufficientFunds: return "Insufficient funds for this trade."
        case .marketClosed: return "Market is currently closed."
        case .invalidOrder: return "Invalid order parameters."
        case .timeout: return "Request timed out."
        }
    }
}

final class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private let baseURL: String
    private let session: URLSession
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private var cancellables = Set<AnyCancellable>()
    
    private init() {
        self.baseURL = "https://api.tradingplatform.com/v1"
        
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        
        self.session = URLSession(configuration: config)
        
        self.decoder = JSONDecoder()
        self.decoder.dateDecodingStrategy = .iso8601
        self.decoder.keyDecodingStrategy = .convertFromSnakeCase
        
        self.encoder = JSONEncoder()
        self.encoder.dateEncodingStrategy = .iso8601
        self.encoder.keyEncodingStrategy = .convertToSnakeCase
    }
    
    private func createRequest(endpoint: String, method: String = "GET", body: Data? = nil) throws -> URLRequest {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else {
            throw APIError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        if let token = try? KeychainManager.shared.getToken() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        let nonce = UUID().uuidString
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(nonce, forHTTPHeaderField: "X-Request-Nonce")
        request.setValue(timestamp, forHTTPHeaderField: "X-Request-Timestamp")
        
        let signaturePayload = "\(method)\(endpoint)\(timestamp)\(nonce)"
        if let signature = generateHMAC(payload: signaturePayload) {
            request.setValue(signature, forHTTPHeaderField: "X-Request-Signature")
        }
        
        return request
    }
    
    private func generateHMAC(payload: String) -> String? {
        guard let secret = try? KeychainManager.shared.retrieve(key: "api_secret") else { return nil }
        guard let payloadData = payload.data(using: .utf8) else { return nil }
        
        var hmac = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        payloadData.withUnsafeBytes { payloadBytes in
            secret.withUnsafeBytes { secretBytes in
                CCHmac(CCHmacAlgorithm(kCCHmacAlgSHA256),
                        secretBytes.baseAddress, secret.count,
                        payloadBytes.baseAddress, payloadData.count,
                        &hmac)
            }
        }
        return Data(hmac).base64EncodedString()
    }
    
    func performRequest<T: Decodable>(endpoint: String, method: String = "GET", body: Encodable? = nil) async throws -> T {
        var bodyData: Data? = nil
        if let body = body {
            bodyData = try encoder.encode(body)
        }
        
        let request = try createRequest(endpoint: endpoint, method: method, body: bodyData)
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw APIError.networkError(NSError(domain: "", code: -1))
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                throw APIError.decodingError
            }
        case 401:
            throw APIError.unauthorized
        case 429:
            throw APIError.rateLimited
        case 500...599:
            throw APIError.serverError(httpResponse.statusCode)
        default:
            throw APIError.serverError(httpResponse.statusCode)
        }
    }
}

