// MARK: - WebSocket Manager for Real-Time Data

protocol WebSocketManagerDelegate: AnyObject {
    func didReceiveMarketData(_ data: MarketData)
    func didReceiveOrderUpdate(_ order: TradeOrder)
    func didDisconnect(error: Error?)
}

final class WebSocketManager: NSObject, URLSessionWebSocketDelegate {
    static let shared = WebSocketManager()
    
    weak var delegate: WebSocketManagerDelegate?
    
    private var webSocket: URLSessionWebSocketTask?
    private var session: URLSession?
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private var subscribedSymbols: Set<String> = []
    private let decoder = JSONDecoder()
    private var pingTimer: Timer?
    
    private override init() {
        super.init()
        decoder.dateDecodingStrategy = .iso8601
        decoder.keyDecodingStrategy = .convertFromSnakeCase
    }
    
    func connect() {
        guard let url = URL(string: "wss://ws.tradingplatform.com/v1/stream") else { return }
        
        let config = URLSessionConfiguration.default
        session = URLSession(configuration: config, delegate: self, delegateQueue: .main)
        
        var request = URLRequest(url: url)
        if let token = try? KeychainManager.shared.getToken() {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        webSocket = session?.webSocketTask(with: request)
        webSocket?.resume()
        
        startReceiving()
        startPingTimer()
    }
    
    func disconnect() {
        pingTimer?.invalidate()
        pingTimer = nil
        webSocket?.cancel(with: .goingAway, reason: nil)
        isConnected = false
    }
    
    func subscribe(to symbols: [String]) {
        symbols.forEach { subscribedSymbols.insert($0) }
        
        let message: [String: Any] = [
            "action": "subscribe",
            "symbols": symbols,
            "channels": ["trades", "quotes", "orders"]
        ]
        
        guard let data = try? JSONSerialization.data(withJSONObject: message),
              let string = String(data: data, encoding: .utf8) else { return }
        
        webSocket?.send(.string(string)) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    func unsubscribe(from symbols: [String]) {
        symbols.forEach { subscribedSymbols.remove($0) }
        
        let message: [String: Any] = [
            "action": "unsubscribe",
            "symbols": symbols
        ]
        
        guard let data = try? JSONSerialization.data(withJSONObject: message),
              let string = String(data: data, encoding: .utf8) else { return }
        
        webSocket?.send(.string(string)) { _ in }
    }
    
    private func startReceiving() {
        webSocket?.receive { [weak self] result in
            switch result {
            case .success(let message):
                self?.handleMessage(message)
                self?.startReceiving()
            case .failure(let error):
                self?.handleDisconnect(error: error)
            }
        }
    }
    
    private func handleMessage(_ message: URLSessionWebSocketTask.Message) {
        switch message {
        case .string(let text):
            guard let data = text.data(using: .utf8) else { return }
            parseMessage(data)
        case .data(let data):
            parseMessage(data)
        @unknown default:
            break
        }
    }
    
    private func parseMessage(_ data: Data) {
        if let marketData = try? decoder.decode(MarketData.self, from: data) {
            DispatchQueue.main.async { [weak self] in
                self?.delegate?.didReceiveMarketData(marketData)
            }
        } else if let orderUpdate = try? decoder.decode(TradeOrder.self, from: data) {
            DispatchQueue.main.async { [weak self] in
                self?.delegate?.didReceiveOrderUpdate(orderUpdate)
            }
        }
    }
    
    private func startPingTimer() {
        pingTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.webSocket?.sendPing { error in
                if let error = error {
                    print("Ping error: \(error)")
                }
            }
        }
    }
    
    private func handleDisconnect(error: Error?) {
        isConnected = false
        pingTimer?.invalidate()
        
        DispatchQueue.main.async { [weak self] in
            self?.delegate?.didDisconnect(error: error)
        }
        
        attemptReconnect()
    }
    
    private func attemptReconnect() {
        guard reconnectAttempts < maxReconnectAttempts else { return }
        
        reconnectAttempts += 1
        let delay = pow(2.0, Double(reconnectAttempts))
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
            if let symbols = self?.subscribedSymbols {
                self?.subscribe(to: Array(symbols))
            }
        }
    }
    
    // MARK: - URLSessionWebSocketDelegate
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didOpenWithProtocol protocol: String?) {
        isConnected = true
        reconnectAttempts = 0
    }
    
    func urlSession(_ session: URLSession, webSocketTask: URLSessionWebSocketTask, didCloseWith closeCode: URLSessionWebSocketTask.CloseCode, reason: Data?) {
        handleDisconnect(error: nil)
    }
}

// MARK: - Trading Service

final class TradingService: ObservableObject {
    static let shared = TradingService()
    
    @Published var portfolio: Portfolio?
    @Published var openOrders: [TradeOrder] = []
    @Published var orderHistory: [TradeOrder] = []
    @Published var watchlist: [WatchlistItem] = []
    @Published var isLoading = false
    @Published var error: APIError?
    
    private let api = SecureAPIClient.shared
    private var cancellables = Set<AnyCancellable>()
    
    private init() {}
    
    // MARK: - Portfolio
    
    func fetchPortfolio() async {
        await MainActor.run { isLoading = true }
        do {
            let portfolio: Portfolio = try await api.performRequest(endpoint: "/portfolio")
            await MainActor.run {
                self.portfolio = portfolio
                self.isLoading = false
            }
        } catch let error as APIError {
            await MainActor.run {
                self.error = error
                self.isLoading = false
            }
        } catch {
            await MainActor.run {
                self.error = .networkError(error)
                self.isLoading = false
            }
        }
    }
    
    // MARK: - Trade Execution
    
    func executeTrade(symbol: String, side: OrderSide, type: OrderType, quantity: Double, limitPrice: Double? = nil, stopPrice: Double? = nil, timeInForce: TimeInForce = .day) async throws -> TradeConfirmation {
        
        guard quantity > 0 else { throw APIError.invalidOrder }
        
        if type == .limit, limitPrice == nil { throw APIError.invalidOrder }
        if type == .stopLoss, stopPrice == nil { throw APIError.invalidOrder }
        if type == .stopLimit, limitPrice == nil || stopPrice == nil { throw APIError.invalidOrder }
        
        if side == .buy {
            let estimatedCost = (limitPrice ?? 0) * quantity
            if let portfolio = portfolio, estimatedCost > portfolio.cashBalance && type == .limit {
                throw APIError.insufficientFunds
            }
        }
        
        if side == .sell {
            let position = portfolio?.positions.first { $0.symbol == symbol }
            if let position = position, quantity > position.quantity {
                throw APIError.invalidOrder
            } else if position == nil {
                throw APIError.invalidOrder
            }
        }
        
        struct OrderRequest: Encodable {
            let symbol: String
            let side: OrderSide
            let type: OrderType
            let quantity: Double
            let limitPrice: Double?
            let stopPrice: Double?
            let timeInForce: TimeInForce
        }
        
        let orderRequest = OrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            timeInForce: timeInForce
        )
        
        let confirmation: TradeConfirmation = try await api.performRequest(
            endpoint: "/orders",
            method: "POST",
            body: orderRequest
        )
        
        await fetchPortfolio()
        await fetchOpenOrders()
        
        return confirmation
    }
    
    func cancelOrder(orderId: String) async throws {
        struct EmptyResponse: Decodable {}
        let _: EmptyResponse = try await api.performRequest(
            endpoint: "/orders/\(orderId)",
            method: "DELETE"
        )
        await fetchOpenOrders()
    }
    
    func modifyOrder(orderId: String, quantity: Double? = nil, limitPrice: Double? = nil, stopPrice: Double? = nil) async throws -> TradeOrder {
        struct ModifyRequest: Encodable {
            let quantity: Double?
            let limitPrice: Double?
            let stopPrice: Double?
        }
        
        let request = ModifyRequest(quantity: quantity, limitPrice: limitPrice, stopPrice: stopPrice)
        
        let order: TradeOrder = try await api.performRequest(
            endpoint: "/orders/\(orderId)",
            method: "PATCH",
            body: request
        )
        
        await fetchOpenOrders()
        return order
    }
    
    // MARK: - Orders
    
    func fetchOpenOrders() async {
        do {
            let orders: [TradeOrder] = try await api.performRequest(endpoint: "/orders?status=open")
            await MainActor.run {
                self.openOrders = orders
            }
        } catch {}
    }
    
    func fetchOrderHistory() async {
        do {
            let orders: [TradeOrder] = try await api.performRequest(endpoint: "/orders/history")
            await MainActor.run {
                self.orderHistory = orders
            }
        } catch {}
    }
    
    // MARK: - Market Data
    
    func getQuote(symbol: String) async throws -> Stock {
        return try await api.performRequest(endpoint: "/quotes/\(symbol)")
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        return try await api.performRequest(endpoint: "/search?q=\(query.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? query)")
    }
    
    // MARK: - Watchlist
    
    func fetchWatchlist() async {
        do {
            let items: [WatchlistItem] = try await api.performRequest(endpoint: "/watchlist")
            await MainActor.run {
                self.watchlist = items
            }
        } catch {}
    }
    
    func addToWatchlist(symbol: String) async throws {
        struct AddRequest: Encodable { let symbol: String }
        let item: WatchlistItem = try await api.performRequest(
            endpoint: "/watchlist",
            method: "POST",
            body: AddRequest(symbol: symbol)
        )
        await MainActor.run {
            self.watchlist.append(item)
        }
    }
    
    func removeFromWatchlist(id: String) async throws {
        struct EmptyResponse: Decodable {}
        let _: EmptyResponse = try await api.performRequest(
            endpoint: "/watchlist/\(id)",
            method: "DELETE"
        )
        await MainActor.run {
            self.watchlist.removeAll { $0.id == id }
        }
    }
}

