@MainActor
final class TradeViewModel: ObservableObject {
    @Published var stock: Stock?
    @Published var orderSide: OrderSide = .buy
    @Published var orderType: OrderType = .market
    @Published var quantity: String = ""
    @Published var limitPrice: String = ""
    @Published var stopPrice: String = ""
    @Published var timeInForce: TimeInForce = .day
    @Published var isExecuting = false
    @Published var confirmation: TradeConfirmation?
    @Published var errorMessage: String?
    @Published var showConfirmation = false
    
    private let tradingService = TradingService.shared
    
    var estimatedCost: Double {
        guard let qty = Double(quantity), qty > 0 else { return 0 }
        let price: Double
        switch orderType {
        case .market:
            price = orderSide == .buy ? (stock?.ask ?? 0) : (stock?.bid ?? 0)
        case .limit, .stopLimit:
            price = Double(limitPrice) ?? 0
        case .stopLoss:
            price = Double(stopPrice) ?? 0
        }
        return qty * price
    }
    
    var isValid: Bool {
        guard let qty = Double(quantity), qty > 0 else { return false }
        
        switch orderType {
        case .market:
            return true
        case .limit:
            return Double(limitPrice) != nil && Double(limitPrice)! > 0
        case .stopLoss:
            return Double(stopPrice) != nil && Double(stopPrice)! > 0
        case .stopLimit:
            return Double(limitPrice) != nil && Double(limitPrice)! > 0 &&
                   Double(stopPrice) != nil && Double(stopPrice)! > 0
        }
    }
    
    var availableQuantity: Double {
        guard let stock = stock else { return 0 }
        if orderSide == .sell {
            return tradingService.portfolio?.positions.first { $0.symbol == stock.symbol }?.quantity ?? 0
        } else {
            let price = orderType == .limit ? (Double(limitPrice) ?? stock.ask) : stock.ask
            guard price > 0 else { return 0 }
            return floor((tradingService.portfolio?.cashBalance ?? 0) / price)
        }
    }
    
    func loadQuote(symbol: String) {
        Task {
            do {
                self.stock = try await tradingService.getQuote(symbol: symbol)
            } catch let error as APIError {
                self.errorMessage = error.errorDescription
            } catch {
                self.errorMessage = error.localizedDescription
            }
        }
    }
    
    func executeTrade() {
        guard isValid, let symbol = stock?.symbol else { return }
        
        isExecuting = true
        errorMessage = nil
        
        Task {
            do {
                let result = try await tradingService.executeTrade(
                    symbol: symbol,
                    side: orderSide,
                    type: orderType,
                    quantity: Double(quantity)!,
                    limitPrice: Double(limitPrice),
                    stopPrice: Double(stopPrice),
                    timeInForce: timeInForce
                )
                self.confirmation = result
                self.showConfirmation = true
                self.isExecuting = false
            } catch let error as APIError {
                self.errorMessage = error.errorDescription
                self.isExecuting = false
            } catch {
                self.errorMessage = error.localizedDescription
                self.isExecuting = false
            }
        }
    }
    
    func reset() {
        quantity = ""
        limitPrice = ""
        stopPrice = ""
        confirmation = nil
        errorMessage = nil
    }
}

