    func removeFromWatchlist(at offsets: IndexSet) {
        for index in offsets {
            let item = items[index]
            Task {
                try? await tradingService.removeFromWatchlist(id: item.id)
            }
        }
        items.remove(atOffsets: offsets)
    }
}

// MARK: - Views

class PortfolioViewController: UIViewController {
    
    private let viewModel = PortfolioViewModel()
    private var cancellables = Set<AnyCancellable>()
    
    private lazy var scrollView: UIScrollView = {
        let sv = UIScrollView()
        sv.translatesAutoresizingMaskIntoConstraints = false
        sv.refreshControl = refreshControl
        return sv
    }()
    
    private lazy var contentStack: UIStackView = {
        let stack = UIStackView()
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .vertical
        stack.spacing = 16
        stack.layoutMargins = UIEdgeInsets(top: 16, left: 16, bottom: 16, right: 16)
        stack.isLayoutMarginsRelativeArrangement = true
        return stack
    }()
    
    private lazy var refreshControl: UIRefreshControl = {
        let rc = UIRefreshControl()
        rc.addTarget(self, action: #selector(refreshData), for: .valueChanged)
        return rc
    }()
    
    private lazy var totalValueLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 36, weight: .bold)
        label.textAlignment = .center
        return label
    }()
    
    private lazy var dayChangeLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 18, weight: .medium)
        label.textAlignment = .center
        return label
    }()
    
    private lazy var cashBalanceLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 16, weight: .regular)
        label.textColor = .secondaryLabel
        label.textAlignment = .center
        return label
    }()
    
    private lazy var positionsTableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .insetGrouped)
        tv.translatesAutoresizingMaskIntoConstraints = false
        tv.delegate = self
        tv.dataSource = self
        tv.register(PositionCell.self, forCellReuseIdentifier: PositionCell.identifier)
        tv.isScrollEnabled = false
        return tv
    }()
    
    private lazy var activityIndicator: UIActivityIndicatorView = {
        let ai = UIActivityIndicatorView(style: .large)
        ai.translatesAutoresizingMaskIntoConstraints = false
        ai.hidesWhenStopped = true
        return ai
    }()
    
    private var positionsTableHeightConstraint: NSLayoutConstraint?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Portfolio"
        view.backgroundColor = .systemGroupedBackground
        
        setupUI()
        bindViewModel()
        viewModel.loadPortfolio()
        
        WebSocketManager.shared.delegate = self
        WebSocketManager.shared.connect()
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        let summaryStack = UIStackView(arrangedSubviews: [totalValueLabel, dayChangeLabel, cashBalanceLabel])
        summaryStack.axis = .vertical
        summaryStack.spacing = 4
        summaryStack.alignment = .center
        
        let summaryCard = createCardView()
        summaryCard.addSubview(summaryStack)
        summaryStack.translatesAutoresizingMaskIntoConstraints = false
        
        NSLayoutConstraint.activate([
            summaryStack.topAnchor.constraint(equalTo: summaryCard.topAnchor, constant: 20),
            summaryStack.leadingAnchor.constraint(equalTo: summaryCard.leadingAnchor, constant: 16),
            summaryStack.trailingAnchor.constraint(equalTo: summaryCard.trailingAnchor, constant: -16),
            summaryStack.bottomAnchor.constraint(equalTo: summaryCard.bottomAnchor, constant: -20)
        ])
        
        let positionsHeader = UILabel()
        positionsHeader.text = "Positions"
        positionsHeader.font = .systemFont(ofSize: 22, weight: .bold)
        
        contentStack.addArrangedSubview(summaryCard)
        contentStack.addArrangedSubview(positionsHeader)
        contentStack.addArrangedSubview(positionsTableView)
        
        positionsTableHeightConstraint = positionsTableView.heightAnchor.constraint(equalToConstant: 200)
        positionsTableHeightConstraint?.isActive = true
        
        view.addSubview(activityIndicator)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor),
            
            activityIndicator.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            activityIndicator.centerYAnchor.constraint(equalTo: view.centerYAnchor)
        ])
    }
    
    private func createCardView() -> UIView {
        let card = UIView()
        card.backgroundColor = .secondarySystemGroupedBackground
        card.layer.cornerRadius = 12
        card.layer.shadowColor = UIColor.black.cgColor
        card.layer.shadowOpacity = 0.1
        card.layer.shadowOffset = CGSize(width: 0, height: 2)
        card.layer.shadowRadius = 4
        return card
    }
    
    private func bindViewModel() {
        viewModel.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.updateUI(with: portfolio)
            }
            .store(in: &cancellables)
        
        viewModel.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isLoading in
                if isLoading {
                    self?.activityIndicator.startAnimating()
                } else {
                    self?.activityIndicator.stopAnimating()
                    self?.refreshControl.endRefreshing()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updateUI(with portfolio: Portfolio?) {
        guard let portfolio = portfolio else { return }
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        
        totalValueLabel.text = formatter.string(from: NSNumber(value: portfolio.totalValue))
        
        let changeSign = portfolio.dayChange >= 0 ? "+" : ""
        dayChangeLabel.text = "\(changeSign)\(formatter.string(from: NSNumber(value: portfolio.dayChange)) ?? "$0.00") (\(String(format: "%+.2f%%", portfolio.dayChangePercent)))"
        dayChangeLabel.textColor = portfolio.dayChange >= 0 ? .systemGreen : .systemRed
        
        cashBalanceLabel.text = "Cash: \(formatter.string(from: NSNumber(value: portfolio.cashBalance)) ?? "$0.00")"
        
        positionsTableView.reloadData()
        
        let rowHeight: CGFloat = 72
        let headerHeight: CGFloat = 44
        let count = CGFloat(portfolio.positions.count)
        positionsTableHeightConstraint?.constant = (count * rowHeight) + headerHeight + 40
    }
    
    @objc private func refreshData() {
        viewModel.refresh()
    }
}

extension PortfolioViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return viewModel.portfolio?.positions.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        guard let cell = tableView.dequeueReusableCell(withIdentifier: PositionCell.identifier, for: indexPath) as? PositionCell,
              let position = viewModel.portfolio?.positions[indexPath.row] else {
            return UITableViewCell()
        }
        cell.configure(with: position)
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 72
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        guard let position = viewModel.portfolio?.positions[indexPath.row] else { return }
        let tradeVC = TradeViewController(symbol: position.symbol)
        navigationController?.pushViewController(tradeVC, animated: true)
    }
}

extension PortfolioViewController: WebSocketManagerDelegate {
    func didReceiveMarketData(_ data: MarketData) {
        guard var portfolio = viewModel.portfolio else { return }
        if let index = portfolio.positions.firstIndex(where: { $0.symbol == data.symbol }) {
            portfolio.positions[index].currentPrice = data.price
            viewModel.portfolio = portfolio
        }
    }
    
    func didReceiveOrderUpdate(_ order: TradeOrder) {
        if order.status == .filled {
            viewModel.loadPortfolio()
        }
    }
    
    func didDisconnect(error: Error?) {
        // Handle disconnect - could show banner
    }
}

