    private lazy var quantityField: UITextField = {
        let tf = createTextField(placeholder: "Quantity")
        tf.keyboardType = .decimalPad
        tf.addTarget(self, action: #selector(quantityChanged), for: .editingChanged)
        return tf
    }()
    
    private lazy var limitPriceField: UITextField = {
        let tf = createTextField(placeholder: "Limit Price")
        tf.keyboardType = .decimalPad
        tf.isHidden = true
        tf.addTarget(self, action: #selector(limitPriceChanged), for: .editingChanged)
        return tf
    }()
    
    private lazy var stopPriceField: UITextField = {
        let tf = createTextField(placeholder: "Stop Price")
        tf.keyboardType = .decimalPad
        tf.isHidden = true
        tf.addTarget(self, action: #selector(stopPriceChanged), for: .editingChanged)
        return tf
    }()
    
    private lazy var timeInForceControl: UISegmentedControl = {
        let items = TimeInForce.allCases.map { $0.rawValue }
        let sc = UISegmentedControl(items: items)
        sc.selectedSegmentIndex = 0
        sc.addTarget(self, action: #selector(timeInForceChanged), for: .valueChanged)
        return sc
    }()
    
    private lazy var estimatedCostLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 16, weight: .medium)
        label.textAlignment = .center
        label.textColor = .secondaryLabel
        return label
    }()
    
    private lazy var availableLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 14, weight: .regular)
        label.textAlignment = .center
        label.textColor = .tertiaryLabel
        return label
    }()
    
    private lazy var executeButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Review Order", for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 18, weight: .bold)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.setTitleColor(.white.withAlphaComponent(0.5), for: .disabled)
        button.layer.cornerRadius = 12
        button.heightAnchor.constraint(equalToConstant: 50).isActive = true
        button.addTarget(self, action: #selector(reviewOrder), for: .touchUpInside)
        button.isEnabled = false
        return button
    }()
    
    private lazy var errorLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 14, weight: .medium)
        label.textColor = .systemRed
        label.textAlignment = .center
        label.numberOfLines = 0
        label.isHidden = true
        return label
    }()
    
    private lazy var activityIndicator: UIActivityIndicatorView = {
        let ai = UIActivityIndicatorView(style: .medium)
        ai.color = .white
        ai.hidesWhenStopped = true
        return ai
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = symbol
        view.backgroundColor = .systemGroupedBackground
        
        setupUI()
        bindViewModel()
        viewModel.loadQuote(symbol: symbol)
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        let priceStack = UIStackView(arrangedSubviews: [priceLabel, changeLabel])
        priceStack.axis = .vertical
        priceStack.spacing = 4
        
        let orderTypeLabel = createSectionLabel("Order Type")
        let quantityLabel = createSectionLabel("Quantity")
        let tifLabel = createSectionLabel("Time In Force")
        
        contentStack.addArrangedSubview(priceStack)
        contentStack.addArrangedSubview(segmentedControl)
        contentStack.addArrangedSubview(orderTypeLabel)
        contentStack.addArrangedSubview(orderTypeControl)
        contentStack.addArrangedSubview(quantityLabel)
        contentStack.addArrangedSubview(quantityField)
        contentStack.addArrangedSubview(limitPriceField)
        contentStack.addArrangedSubview(stopPriceField)
        contentStack.addArrangedSubview(tifLabel)
        contentStack.addArrangedSubview(timeInForceControl)
        contentStack.addArrangedSubview(estimatedCostLabel)
        contentStack.addArrangedSubview(availableLabel)
        contentStack.addArrangedSubview(errorLabel)
        contentStack.addArrangedSubview(executeButton)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor)
        ])
    }
    
    private func createTextField(placeholder: String) -> UITextField {
        let tf = UITextField()
        tf.placeholder = placeholder
        tf.borderStyle = .roundedRect
        tf.font = .systemFont(ofSize: 17)
        tf.heightAnchor.constraint(equalToConstant: 44).isActive = true
        tf.backgroundColor = .secondarySystemGroupedBackground
        return tf
    }
    
    private func createSectionLabel(_ text: String) -> UILabel {
        let label = UILabel()
        label.text = text
        label.font = .systemFont(ofSize: 14, weight: .medium)
        label.textColor = .secondaryLabel
        return label
    }
    
    private func bindViewModel() {
        viewModel.$stock
            .receive(on: DispatchQueue.main)
            .sink { [weak self] stock in
                self?.updatePriceDisplay(stock)
            }
            .store(in: &cancellables)
        
        viewModel.$errorMessage
            .receive(on: DispatchQueue.main)
            .sink { [weak self] message in
                self?.errorLabel.text = message
                self?.errorLabel.isHidden = message == nil
            }
            .store(in: &cancellables)
        
        viewModel.$isExecuting
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isExecuting in
                self?.executeButton.isEnabled = !isExecuting && (self?.viewModel.isValid ?? false)
                if isExecuting {
                    self?.executeButton.setTitle("", for: .normal)
                    self?.activityIndicator.startAnimating()
                    self?.executeButton.addSubview(self!.activityIndicator)
                    self?.activityIndicator.center = CGPoint(x: self!.executeButton.bounds.midX, y: self!.executeButton.bounds.midY)
                } else {
                    self?.activityIndicator.stopAnimating()
                    self?.activityIndicator.removeFromSuperview()
                    self?.executeButton.setTitle("Review Order", for: .normal)
                }
            }
            .store(in: &cancellables)
        
        viewModel.$showConfirmation
            .receive(on: DispatchQueue.main)
            .sink { [weak self] show in
                if show {
                    self?.showTradeConfirmation()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updatePriceDisplay(_ stock: Stock?) {
        guard let stock = stock else { return }
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        priceLabel.text = formatter.string(from: NSNumber(value: stock.currentPrice))
        
        let changeSign = stock.change >= 0 ? "+" : ""
        changeLabel.text = "\(changeSign)\(formatter.string(from: NSNumber(value: stock.change)) ?? "") (\(String(format: "%+.2f%%", stock.changePercent)))"
        changeLabel.textColor = stock.change >= 0 ? .systemGreen : .systemRed
        
        updateEstimatedCost()
        updateAvailableLabel()
    }
    
    private func updateEstimatedCost() {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        let cost = viewModel.estimatedCost
        estimatedCostLabel.text = "Estimated \(viewModel.orderSide == .buy ? "Cost" : "Proceeds"): \(formatter.string(from: NSNumber(value: cost)) ?? "$0.00")"
    }
    
    private func updateAvailableLabel() {
        let available = viewModel.availableQuantity
        if viewModel.orderSide == .buy {
            availableLabel.text = "Max purchasable: \(String(format: "%.0f", available)) shares"
        } else {
            availableLabel.text = "Available to sell: \(String(format: "%.2f", available)) shares"
        }
    }
    
    private func updateFieldVisibility() {
        UIView.animate(withDuration: 0.25) {
            switch self.viewModel.orderType {
            case .market:
                self.limitPriceField.isHidden = true
                self.stopPriceField.isHidden = true
            case .limit:
                self.limitPriceField.isHidden = false
                self.stopPriceField.isHidden = true
            case .stopLoss:
                self.limitPriceField.isHidden = true
                self.stopPriceField.isHidden = false
            case .stopLimit:
                self.limitPriceField.isHidden = false
                self.stopPriceField.isHidden = false
            }
        }
    }
    
    @objc private func sideChanged() {
        viewModel.orderSide = segmentedControl.selectedSegmentIndex == 0 ? .buy : .sell
        executeButton.backgroundColor = viewModel.orderSide == .buy ? .systemGreen : .systemRed
        updateEstimatedCost()
        updateAvailableLabel()
        validateOrder()
    }
    
    @objc private func orderTypeChanged() {
        viewModel.orderType = OrderType.allCases[orderTypeControl.selectedSegmentIndex]
        updateFieldVisibility()
        updateEstimatedCost()
        validateOrder()
    }
    
    @objc private func quantityChanged() {
        viewModel.quantity = quantityField.text ?? ""
        updateEstimatedCost()
        validateOrder()
    }
    
    @objc private func limitPriceChanged() {
        viewModel.limitPrice = limitPriceField.text ?? ""
        updateEstimatedCost()
        validateOrder()
    }
    
    @objc private func stopPriceChanged() {
        viewModel.stopPrice = stopPriceField.text ?? ""
        validateOrder()
    }
    
    @objc private func timeInForceChanged() {
        viewModel.timeInForce = TimeInForce.allCases[timeInForceControl.selectedSegmentIndex]
    }
    
    private func validateOrder() {
        executeButton.isEnabled = viewModel.isValid
    }
    
    @objc private func reviewOrder() {
        guard viewModel.isValid else { return }
        showOrderReview()
    }
    
    private func showOrderReview() {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        let alert = UIAlertController(
            title: "Confirm \(viewModel.orderSide.rawValue) Order",
            message: """
            Symbol: \(symbol)
            Type: \(viewModel.orderType.rawValue)
            Quantity: \(viewModel.quantity)
            \(viewModel.orderType == .limit || viewModel.orderType == .stopLimit ? "Limit Price: \(formatter.string(from: NSNumber(value: Double(viewModel.limitPrice) ?? 0)) ?? "")\n" : "")\
            \(viewModel.orderType == .stopLoss || viewModel.orderType == .stopLimit ? "Stop Price: \(formatter.string(from: NSNumber(value: Double(viewModel.stopPrice) ?? 0)) ?? "")\n" : "")\
            Time in Force: \(viewModel.timeInForce.rawValue)
            Estimated \(viewModel.orderSide == .buy ? "Cost" : "Proceeds"): \(formatter.string(from: NSNumber(value: viewModel.estimatedCost)) ?? "$0.00")
            """,
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Execute", style: .default) { [weak self] _ in
            self?.viewModel.executeTrade()
        })
        
        present(alert, animated: true)
    }
    
    private func showTradeConfirmation() {
        guard let confirmation = viewModel.confirmation else { return }
        
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        
        let alert = UIAlertController(
            title: "Order Executed ✅",
            message: """
            Order ID: \(confirmation.orderId)
            \(confirmation.side.rawValue) \(String(format: "%.2f", confirmation.quantity)) \(confirmation.symbol)
            Price: \(formatter.string(from: NSNumber(value: confirmation.price)) ?? "")
            Total: \(formatter.string(from: NSNumber(value: confirmation.totalAmount)) ?? "")
            Commission: \(formatter.string(from: NSNumber(value: confirmation.commission)) ?? "")
            """,
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Done", style: .default) { [weak self] _ in
            self?.viewModel.reset()
            self?.quantityField.text = ""
            self?.limitPriceField.text = ""
            self?.stopPriceField.text = ""
            self?.navigationController?.popViewController(animated: true)
        })
        
        alert.addAction(UIAlertAction(title: "New Trade", style: .cancel) { [weak self] _ in
            self?.viewModel.reset()
            self?.quantityField.text = ""
            self?.limitPriceField.text = ""
            self?.stopPriceField.text = ""
        })
        
        present(alert, animated: true)
    }
}

